function FileManager({ files, path }) {
  const { div, span, img } = tags;
  const [view, setView] = createSignal('grid');

  return div({ class: css('_flex _col _gap4 _flex1') },
    div({ class: css('_flex _aic _jcsb _flexWrap _gap3') },
      Breadcrumb({ items: path.map((p, i) => ({ label: p, href: '#' })), separator: 'slash' }),
      div({ class: css('_flex _gap2') },
        Button({ variant: view() === 'grid' ? 'primary' : 'outline', size: 'sm', onclick: () => setView('grid') }, icon('grid', { size: '1em' })),
        Button({ variant: view() === 'list' ? 'primary' : 'outline', size: 'sm', onclick: () => setView('list') }, icon('list', { size: '1em' })),
        Button({ variant: 'primary', size: 'sm' }, icon('upload', { size: '1em' }), ' Upload')
      )
    ),
    div({ class: css('_grid _gcaf200 _gap4') },
      ...files.map(file =>
        Card({ hover: true, class: css('_cursor[pointer]') },
          Card.Body({ class: css('_flex _col _aic _gap2 _p4') },
            div({ class: css('_w12 _h12 _flex _center _r2 _bgmuted/20') },
              icon(file.type === 'folder' ? 'folder' : file.type === 'image' ? 'image' : 'file', { size: '1.5rem', class: css('_fgprimary') })
            ),
            span({ class: css('_textsm _bold _tc _truncate _wfull') }, file.name),
            span({ class: css('_textxs _fgmuted') }, file.size || `${file.items} items`)
          )
        )
      )
    )
  );
}
